INSERT INTO flashcards (course_id, question_text, answer_text, difficulty, order_index) VALUES
('10000000-0000-0000-0000-000000000001', 'What is cuckooing in adult safeguarding?', 'Cuckooing is when criminals take over the home of a vulnerable adult to use as a base for illegal activity such as drug dealing. The resident is often coerced or threatened.', 3, 26),
('10000000-0000-0000-0000-000000000001', 'What does trauma-informed care mean in safeguarding?', 'An approach recognising the widespread impact of trauma on behaviour. Staff avoid re-traumatising people and support recovery by creating safe, trustworthy environments.', 2, 27),
('10000000-0000-0000-0000-000000000001', 'What is the role of the Local Authority Designated Officer (LADO)?', 'The LADO manages allegations against staff or volunteers who work with vulnerable adults. They must be notified promptly when an allegation is made about a person in a position of trust.', 3, 28),
('10000000-0000-0000-0000-000000000001', 'What is the duty of candour in safeguarding?', 'A professional and legal obligation to be open and honest with people when something goes wrong with their care — including apologising and explaining what happened.', 2, 29),
('10000000-0000-0000-0000-000000000001', 'When can confidentiality be broken in a safeguarding situation?', 'When there is a serious risk of harm to the person or others, when a crime has been committed, or when required by law. The decision must be recorded and justified.', 2, 30),
('10000000-0000-0000-0000-000000000001', 'What are the signs of emotional or psychological abuse?', 'Low self-esteem, fearfulness, withdrawal, depression, anxiety, changes in behaviour, flinching, or the person appearing nervous when a specific individual is nearby.', 2, 31),
('10000000-0000-0000-0000-000000000001', 'What is meant by contextual safeguarding?', 'Recognising that abuse can occur outside the home — in communities, online, or through peer relationships — and that safeguarding responses must consider these wider contexts.', 3, 32),
('10000000-0000-0000-0000-000000000001', 'What should a safeguarding referral include?', 'The person''s name and address, description of the concern, dates and times, names of any alleged perpetrators, witness information, and any immediate risks.', 2, 33),
('10000000-0000-0000-0000-000000000001', 'What is undue influence in the context of financial abuse?', 'When someone uses their position of power or trust to pressure a vulnerable adult into financial decisions that benefit the influencer. Often subtle and hard to detect.', 3, 34),
('10000000-0000-0000-0000-000000000001', 'What is a safeguarding plan?', 'An agreed set of actions to reduce risk and protect the vulnerable adult. It is developed with the person, their family, and professionals involved in their care.', 2, 35),
('10000000-0000-0000-0000-000000000001', 'What is the difference between safeguarding and protection?', 'Safeguarding is a proactive, preventative approach for all. Protection is a reactive, targeted response when someone is at immediate risk of harm.', 2, 36),
('10000000-0000-0000-0000-000000000001', 'What does best interests decision-making mean?', 'When someone lacks capacity, decisions must be made in their best interests considering their past and present wishes, values, and the views of people close to them.', 2, 37),
('10000000-0000-0000-0000-000000000001', 'What is mate crime in adult safeguarding?', 'When a vulnerable adult is befriended by someone who then exploits or abuses them. The victim may not realise they are being abused because they consider the person a friend.', 3, 38),
('10000000-0000-0000-0000-000000000001', 'Name three signs that may indicate neglect in a care setting.', 'Unwashed appearance, pressure sores from lack of repositioning, significant weight loss, dehydration, dirty clothing, missed medications, or an unkempt living environment.', 2, 39),
('10000000-0000-0000-0000-000000000001', 'What is the purpose of a Safeguarding Adults Conference?', 'To bring together professionals and sometimes the person at risk to share information, assess risk, and agree a coordinated safeguarding plan.', 2, 40),
('10000000-0000-0000-0000-000000000001', 'What is radicalisation and why is it relevant to safeguarding?', 'Radicalisation is the process of being drawn into extremist views. Vulnerable adults can be targeted. Staff have a Prevent duty to recognise signs and report concerns.', 3, 41),
('10000000-0000-0000-0000-000000000001', 'Can a person with capacity choose to remain in an abusive situation?', 'Yes. An adult with capacity has the right to make their own decisions, including staying in a situation others consider unsafe. Staff must respect this, document it, and offer continued support.', 2, 42),
('10000000-0000-0000-0000-000000000001', 'What is a positive safeguarding organisational culture?', 'An environment where staff feel safe to raise concerns, leaders model good practice, safeguarding is embedded in all processes, and lessons from incidents are shared and acted upon.', 2, 43),
('10000000-0000-0000-0000-000000000001', 'What are the signs of sexual abuse in a care setting?', 'Unexplained bruising or soreness in genital areas, torn clothing, sexually transmitted infections, sudden behavioural changes, withdrawal, or distress during personal care.', 3, 44),
('10000000-0000-0000-0000-000000000001', 'What is the personalisation agenda in adult social care?', 'The shift towards tailoring care to individual needs and preferences, giving people control over their own care through personal budgets and individual support planning.', 2, 45),
('10000000-0000-0000-0000-000000000001', 'What should you do if you observe poor practice but not immediate abuse?', 'Report it to your manager, record your observations, and use your organisation''s incident reporting system. Poor practice can escalate to abuse if unchallenged.', 1, 46),
('10000000-0000-0000-0000-000000000001', 'What is a DoLS authorisation?', 'A Deprivation of Liberty Safeguards authorisation allows a care home or hospital to lawfully deprive a person who lacks capacity of their liberty if it is in their best interests.', 3, 47),
('10000000-0000-0000-0000-000000000001', 'Why is accurate record-keeping vital in safeguarding?', 'Records are legal documents, provide evidence for enquiries, ensure continuity of care, and demonstrate that staff acted appropriately. Poor records can jeopardise prosecutions.', 2, 48),
('10000000-0000-0000-0000-000000000001', 'What is positive risk-taking in care?', 'Supporting someone with capacity to take managed risks in order to promote their independence and wellbeing, while putting appropriate safeguards in place.', 2, 49),
('10000000-0000-0000-0000-000000000001', 'What is the think family approach in safeguarding?', 'Considering the needs of the whole family when working with a vulnerable adult, including any children in the household who may also be at risk.', 2, 50)
INSERT INTO quiz_questions (course_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation) VALUES
('10000000-0000-0000-0000-000000000001', 'What is cuckooing?', 'A type of medication error', 'Criminals taking over a vulnerable person''s home for illegal activity', 'A financial fraud technique', 'A form of psychological manipulation', 'B', 'Cuckooing is when criminals occupy a vulnerable adult''s home to use as a base for drug dealing or other criminal activity. The resident is often coerced or threatened and may not feel safe to report it.'),
('10000000-0000-0000-0000-000000000001', 'When can a care worker break confidentiality in safeguarding?', 'Whenever the person asks them not to tell anyone', 'Only when requested by the CQC', 'When there is serious risk of harm, a crime has occurred, or the law requires it', 'Never — confidentiality must always be maintained', 'C', 'Confidentiality can be broken when there is serious risk of harm to the person or others, when a crime has been committed, or when required by law. The decision must be recorded.'),
('10000000-0000-0000-0000-000000000001', 'What does the duty of candour require?', 'To report all incidents to the police', 'To be open and honest with people when something goes wrong with their care', 'To maintain confidentiality at all times', 'To complete a DBS check annually', 'B', 'The duty of candour is a legal and professional obligation to be transparent when things go wrong — including apologising, explaining what happened, and what will be done to prevent recurrence.'),
('10000000-0000-0000-0000-000000000001', 'Can an adult with mental capacity choose to remain in an abusive situation?', 'No — staff must remove them immediately', 'Yes — with capacity they have the right to make their own decisions, and staff must respect this while documenting it', 'No — a Section 42 enquiry must always be opened', 'Yes — but only if the abuser agrees', 'B', 'Adults with capacity have the right to self-determination. If they choose to remain in a situation, staff must respect this, document it clearly, and ensure they know how to get help.'),
('10000000-0000-0000-0000-000000000001', 'What is the purpose of a Safeguarding Adults Board (SAB)?', 'To prosecute perpetrators of abuse', 'To coordinate and ensure effectiveness of safeguarding work locally, publish strategies and review serious cases', 'To provide direct care to vulnerable adults', 'To manage staff complaints', 'B', 'The SAB is a statutory multi-agency body (local authority, NHS, police) that coordinates safeguarding across a local area, publishes strategies, and conducts Safeguarding Adults Reviews.')
